// maxConcurrency:1 ensures executions are sequential — static data writes are always visible
const body  = $input.first().json.body || {};
const msgId = body.idMessage || '';
if (!msgId) return [$input.first()]; // no ID — pass through

const sd   = $getWorkflowStaticData('global');
const seen = sd.seenIds || {};
const now  = Date.now();

// Evict entries older than 2 minutes
for (const k in seen) { if (now - seen[k] > 120000) delete seen[k]; }

if (seen[msgId]) return []; // duplicate — drop silently

seen[msgId] = now;
sd.seenIds  = seen;
return [$input.first()];

const body = $input.first().json.body;
const chatId     = body.senderData?.chatId || '';
const senderName = body.senderData?.senderName || chatId;

// ── Extract text from all message types ──
const msgData = body.messageData || {};
const typeMsg  = msgData.typeMessage || '';
let msgText = '';
if (typeMsg === 'textMessage') {
  msgText = msgData.textMessageData?.textMessage || '';
} else if (typeMsg === 'extendedTextMessage') {
  msgText = msgData.extendedTextMessageData?.text || '';
} else if (typeMsg === 'quotedMessage') {
  msgText = msgData.extendedTextMessageData?.text || msgData.quotedMessage?.textMessage || '';
}

// Skip if no readable text
if (!msgText.trim()) return [];

const CONTEXT = "You are the WhatsApp order assistant for BANKO CHOW, a Lagos street burger restaurant.\n\n" +
"BANKO CHOW MENU:\n" +
"STREET BURGERS\n" +
"- MAINLAND (Agege Bread, Ram Suya, Lettuce, Tomatoes, Banko Special Sauce) - N4,000\n" +
"- ISLAND (Agege Bread, Shredded Chicken, Lettuce, Tomatoes, Banko Special Sauce) - N4,500\n" +
"- LINKBRIDGE (Agege Bread, Ram Suya + Shredded Chicken, Lettuce, Tomatoes, Banko Special Sauce) - N5,000\n\n" +
"CHOP LIFE MINI BURGER\n" +
"- Box of 10 - N23,000\n" +
"- Box of 20 - N40,000\n\n" +
"DRINKS: ZOBO - N1,500\n\n" +
"EXTRAS: Sausage N1,000 | Cheese N1,000 | Banko Special Sauce N5,000\n\n" +
"RULES:\n" +
"1. NEVER use the customer's name in any reply. Say 'Hi' or 'Hello' only — no names ever.\n" +
"2. Always share the full menu when greeting a new customer or when they ask. Do not repeat it in every single reply, but always show it at the start of a conversation.\n" +
"3. DELIVERY FEE: If the customer says they want delivery, add a flat fee of N3,000 to the total. If they say pickup or do not mention delivery, no delivery fee.\n" +
"4. To place an order - collect items, name, phone, delivery address (or pickup), delivery time.\n" +
"5. Show order summary with total (including delivery fee if applicable), then share payment: GTBank | Banko Chow Ltd | 0123456789. Ask for proof of payment.\n" +
"6. Once the customer indicates payment in ANY way — sending a screenshot, saying 'done', 'sent', 'transferred', 'I paid', 'check it', 'I have paid', or anything that suggests they made the transfer — treat it as payment confirmed and end your reply with the ORDER_CONFIRMED marker. Use your judgement. Do NOT confirm before there is any indication of payment.\n" +
"7. Be warm, use emojis. Delivery takes 45-60 mins.\n\n" +
"After customer confirms payment, end your reply with exactly:\n" +
'ORDER_CONFIRMED: {"orderId":"BCH-YYYYMMDD-XXXX","customerName":"ACTUAL_NAME","phone":"ACTUAL_PHONE","items":"ACTUAL_ITEMS","total":NUMERIC_TOTAL,"deliveryFee":3000_OR_0,"wantsDelivery":true_OR_false,"address":"ACTUAL_ADDRESS","deliveryTime":"ACTUAL_TIME","paymentMethod":"Bank Transfer","status":"Pending Verification"}' +
'\nIMPORTANT: wantsDelivery must be true if customer gave a delivery address, false if pickup. deliveryFee must be 3000 for delivery, 0 for pickup. total must be a number, not a string.';

return [{ json: {
  chatId, senderName, msgText,
  fullMessage: CONTEXT + "\n\n---\nCustomer (" + senderName + ") says: " + msgText
}}];

const out    = $input.first().json.output || $input.first().json.text || '';
const chatId = $('Prepare Agent Input').first().json.chatId;

const match = out.match(/ORDER_CONFIRMED:\s*(\{[\s\S]+?\})/);
let orderData = null, cleanReply = out;

if (match) {
  try {
    orderData  = JSON.parse(match[1]);
    cleanReply = out.replace(/ORDER_CONFIRMED:[\s\S]*$/, '').trim();
  } catch(e) { /* keep cleanReply as full output */ }
}

return [{ json: { reply: cleanReply, hasOrder: orderData !== null, orderData, chatId } }];

const d = $input.first().json;
const o = d.orderData || {};
const now = new Date();

const orderId      = o.orderId || ('BCH-' + now.toISOString().slice(0,10).replace(/-/g,'') + '-' + String(Math.floor(1000+Math.random()*9000)));
const total        = Number(o.total) || 0;
const deliveryFee  = Number(o.deliveryFee) || 0;
const wantsDelivery = o.wantsDelivery === true || o.wantsDelivery === 'true' || deliveryFee > 0;
const deliveryLine = wantsDelivery ? 'Delivery (fee: N' + deliveryFee.toLocaleString() + ')' : 'Pickup (no delivery fee)';

return [{ json: {
  orderId, channel: 'WhatsApp', status: o.status || 'Pending Verification',
  customerName: o.customerName || '',
  phone: o.phone || d.chatId,
  address: o.address || '',
  items: o.items || '',
  total,
  deliveryFee,
  wantsDelivery,
  deliveryTime: o.deliveryTime || 'ASAP',
  paymentMethod: o.paymentMethod || 'Bank Transfer',
  timestamp: now.toISOString(),
  orderSummary: 'ORDER: ' + orderId + '\nName: ' + (o.customerName||'') + '\nPhone: ' + (o.phone||d.chatId) +
    '\nAddress: ' + (o.address||'Pickup') + '\nItems: ' + (o.items||'') +
    '\nSubtotal: N' + (total - deliveryFee).toLocaleString() +
    (wantsDelivery ? '\nDelivery Fee: N' + deliveryFee.toLocaleString() : '') +
    '\nTOTAL: N' + total.toLocaleString() +
    '\n' + deliveryLine +
    '\nPreferred Time: ' + (o.deliveryTime||'ASAP') + '\nPayment: ' + (o.paymentMethod||'Bank Transfer') +
    '\nChannel: WhatsApp\nStatus: Pending Verification',
  reply: d.reply,
  chatId: d.chatId
}}];

const d = $input.first().json;
const orderPayload = {
  orderId: d.orderId, customerName: d.customerName, phone: d.phone,
  items: d.items, total: d.total, deliveryFee: d.deliveryFee || 0,
  wantsDelivery: d.wantsDelivery || false,
  address: d.address, deliveryTime: d.deliveryTime,
  paymentMethod: d.paymentMethod, chatId: d.chatId,
  timestamp: d.timestamp, channel: d.channel,
  orderSummary: d.orderSummary
};
const orderStr = Buffer.from(JSON.stringify(orderPayload)).toString('base64');
const BASE_URL = 'https://efiayomide.app.n8n.cloud/webhook/banko-chow-payment';
const approveUrl = BASE_URL + '?action=approve&order=' + encodeURIComponent(orderStr);
const rejectUrl  = BASE_URL + '?action=reject&order='  + encodeURIComponent(orderStr);
return [{ json: { ...d, approveUrl, rejectUrl } }];

