const qs = $input.first().json.query || {};
const action = qs.action || 'approve';
const orderStr = qs.order || '';
let order = {};
try {
  order = JSON.parse(Buffer.from(decodeURIComponent(orderStr), 'base64').toString('utf8'));
} catch(e) { order = { error: 'Invalid order data' }; }
return [{ json: { action, ...order } }];

