const orderItems = $('Decode Order').first().json.items || '';
const inventory  = $input.all();

const itemMap = {};
orderItems.split(',').map(s => s.trim()).forEach(part => {
  const m1 = part.match(/^(\d+)\s*x?\s+(.+)$/i);
  const m2 = part.match(/^(.+?)\s+x(\d+)$/i);
  const m = m1 || m2;
  if (m) {
    const qty  = parseInt(m1 ? m[1] : m[2]);
    const name = (m1 ? m[2] : m[1]).trim().toLowerCase();
    itemMap[name] = (itemMap[name] || 0) + qty;
  }
});

const updates = [];
for (const row of inventory) {
  const product = (row.json.Product || '').toLowerCase();
  for (const [itemName, qty] of Object.entries(itemMap)) {
    if (product.includes(itemName) || itemName.includes(product)) {
      const current = parseInt(row.json.Available) || 0;
      updates.push({ Product: row.json.Product, Available: Math.max(0, current - qty) });
      break;
    }
  }
}

return updates.length ? updates.map(u => ({ json: u })) : [{ json: { skipped: true } }];
